import React, { useState } from 'react';
import { Button, Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatVnd, formatNumber } from '../../../utils/formatters';
import { exportExcel, MONTH_OPTIONS, YEAR_OPTIONS } from '../../../utils/exportExcel';
import styles from '../../../styles/erpReportPage.module.css';

import { BarChart, Bar, LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import type { KpiMetrics, MonthlyTrendRow } from '../../../services/analytics/models';
const PhanTichPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [year, setYear] = useState(now.getFullYear());
  const [kpi, setKpi] = useState<KpiMetrics | null>(null);
  const [trend, setTrend] = useState<MonthlyTrendRow[]>([]);
  const [loading, setLoading] = useState(false);
  React.useEffect(() => { let c=false; setLoading(true); const t=setTimeout(()=>{ Promise.all([analyticsService.getKpiMetrics({month,year}), analyticsService.getMonthlyTrend({year})])
    .then(([k,t])=>{if(!c){setKpi(k);setTrend(t);}}).catch(e=>{if(!c)dispatch(addToast({message:e?.message??'Lỗi',type:'error'}));}).finally(()=>{if(!c)setLoading(false);}); },0); return ()=>{c=true;clearTimeout(t);}; }, [month,year,dispatch]);
  const chartData = trend.map(d=>({ name:`T${d.month}`, revenue:d.revenue, cogs:d.cogs }));
  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}><div className={styles.titleBlock}><h1 className={styles.title}><i className="fas fa-chart-pie" /> Phân tích kinh doanh</h1><p className={styles.subtitle}>T{month}/{year}</p></div>
        <div className={styles.headerActions}><Select value={String(month)} onChange={e=>setMonth(Number(e.target.value))} options={MONTH_OPTIONS} size="small" /><Select value={String(year)} onChange={e=>setYear(Number(e.target.value))} options={YEAR_OPTIONS} size="small" /></div></div>
      {loading?<div className={styles.loading}><i className="fas fa-spinner fa-spin" /></div>:<>
      <div className={styles.kpiGrid}>
        <div className={styles.kpiCard}><div className={styles.kpiLabel}>Doanh thu</div><div className={styles.kpiValue}>{formatVnd(kpi?.revenue)}</div></div>
        <div className={styles.kpiCard}><div className={styles.kpiLabel}>Giá vốn</div><div className={styles.kpiValue}>{formatVnd(kpi?.cogs)}</div></div>
        <div className={styles.kpiCard}><div className={styles.kpiLabel}>Biên LN gộp</div><div className={styles.kpiValue}>{formatNumber(kpi?.grossMargin)}%</div></div>
        <div className={styles.kpiCard}><div className={styles.kpiLabel}>Đơn hàng</div><div className={styles.kpiValue}>{formatNumber(kpi?.orders)}</div></div>
      </div>
      <div className={styles.chartCard}><ResponsiveContainer width="100%" height={280}><BarChart data={chartData}><CartesianGrid strokeDasharray="3 3" /><XAxis dataKey="name" /><YAxis tickFormatter={v=>`${(v/1e9).toFixed(1)}B`} /><Tooltip formatter={(v:number)=>formatVnd(v)} /><Legend /><Bar dataKey="revenue" name="Doanh thu" fill="#1677ff" /><Bar dataKey="cogs" name="Giá vốn" fill="#fa8c16" /></BarChart></ResponsiveContainer></div>
      </>}
    </div>
  );
};
export default PhanTichPage;
